    SELECT menu_seq.NEXTVAL FROM dual

INSERT INTO menu_tbl (
menu_id, store_id, menu_name, menu_info, menu_price, menu_category, menu_image, menu_status
) VALUES (
#{menuId}, #{storeId}, #{menuName}, #{menuInfo}, #{menuPrice}, #{menuCategory}, #{menuImage}, 1
)


    SELECT option_seq.NEXTVAL FROM dual

INSERT INTO option_tbl (
option_no, option_type, option_name, option_price
) VALUES (
#{optionNo}, #{optionType}, #{optionName}, #{optionPrice}
)
